// TGT Logo - The Green Tangerine circular logo (actual logo, base64 PNG)
// Circular crop of the original logo with dark disc background

// Base64-encoded circular PNG logo
const TGT_LOGO_BASE64 = '';

// Inline HTML img tag for embedding in PDF templates
export const TGT_LOGO_SVG = `<img src="data:image/png;base64,${TGT_LOGO_BASE64}" style="width:100%;height:100%;object-fit:contain;" />`;

// Data URI for use in HTML img tags directly
export function getLogoDataUri(): string {
  return `data:image/png;base64,${TGT_LOGO_BASE64}`;
}
